1	<!DOCTYPE html>
2	<html lang="ru">
3	<head>
4	    <meta charset="UTF-8">
5	    <meta name="viewport" content="width=device-width, initial-scale=1.0">
6	    <title>Downloads Audit Dashboard</title>
7	    <script src="https://cdn.jsdelivr.net/npm/chart.js@4.4.1/dist/chart.umd.min.js"></script>
8	    <link href="https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700&display=swap" rel="stylesheet">
9	    <style>
10	        * {
11	            margin: 0;
12	            padding: 0;
13	            box-sizing: border-box;
14	        }
15	
16	        body {
17	            font-family: 'Inter', -apple-system, BlinkMacSystemFont, sans-serif;
18	            background: #0d1117;
19	            color: #e6edf3;
20	            min-height: 100vh;
21	            padding: 32px;
22	        }
23	
24	        .container {
25	            max-width: 1200px;
26	            margin: 0 auto;
27	        }
28	
29	        h1 {
30	            font-size: 28px;
31	            font-weight: 700;
32	            margin-bottom: 8px;
33	            background: linear-gradient(135deg, #58a6ff, #a371f7);
34	            -webkit-background-clip: text;
35	            -webkit-text-fill-color: transparent;
36	            background-clip: text;
37	        }
38	
39	        .subtitle {
40	            color: #8b949e;
41	            font-size: 14px;
42	            margin-bottom: 32px;
43	        }
44	
45	        .stats-grid {
46	            display: grid;
47	            grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
48	            gap: 16px;
49	            margin-bottom: 32px;
50	        }
51	
52	        .stat-card {
53	            background: #161b22;
54	            border: 1px solid #30363d;
55	            border-radius: 12px;
56	            padding: 20px;
57	            transition: transform 0.2s, box-shadow 0.2s;
58	        }
59	
60	        .stat-card:hover {
61	            transform: translateY(-2px);
62	            box-shadow: 0 8px 24px rgba(0,0,0,0.4);
63	        }
64	
65	        .stat-value {
66	            font-size: 32px;
67	            font-weight: 700;
68	            color: #58a6ff;
69	        }
70	
71	        .stat-label {
72	            font-size: 13px;
73	            color: #8b949e;
74	            margin-top: 4px;
75	        }
76	
77	        .dashboard-grid {
78	            display: grid;
79	            grid-template-columns: 1fr 1fr;
80	            gap: 24px;
81	        }
82	
83	        @media (max-width: 900px) {
84	            .dashboard-grid {
85	                grid-template-columns: 1fr;
86	            }
87	        }
88	
89	        .card {
90	            background: #161b22;
91	            border: 1px solid #30363d;
92	            border-radius: 12px;
93	            padding: 24px;
94	        }
95	
96	        .card-title {
97	            font-size: 16px;
98	            font-weight: 600;
99	            margin-bottom: 20px;
100	            display: flex;
101	            align-items: center;
102	            gap: 8px;
103	        }
104	
105	        .card-title::before {
106	            content: '';
107	            width: 4px;
108	            height: 16px;
109	            background: linear-gradient(180deg, #58a6ff, #a371f7);
110	            border-radius: 2px;
111	        }
112	
113	        .chart-container {
114	            position: relative;
115	            height: 300px;
116	        }
117	
118	        .file-list {
119	            max-height: 400px;
120	            overflow-y: auto;
121	        }
122	
123	        .file-list::-webkit-scrollbar {
124	            width: 6px;
125	        }
126	
127	        .file-list::-webkit-scrollbar-track {
128	            background: #0d1117;
129	            border-radius: 3px;
130	        }
131	
132	        .file-list::-webkit-scrollbar-thumb {
133	            background: #30363d;
134	            border-radius: 3px;
135	        }
136	
137	        .file-item {
138	            display: flex;
139	            align-items: center;
140	            padding: 12px;
141	            border-bottom: 1px solid #21262d;
142	            transition: background 0.15s;
143	        }
144	
145	        .file-item:last-child {
146	            border-bottom: none;
147	        }
148	
149	        .file-item:hover {
150	            background: #1c2128;
151	        }
152	
153	        .file-rank {
154	            width: 28px;
155	            height: 28px;
156	            border-radius: 6px;
157	            background: #21262d;
158	            display: flex;
159	            align-items: center;
160	            justify-content: center;
161	            font-size: 12px;
162	            font-weight: 600;
163	            margin-right: 12px;
164	            flex-shrink: 0;
165	        }
166	
167	        .file-rank.top3 {
168	            background: linear-gradient(135deg, #58a6ff, #a371f7);
169	            color: #0d1117;
170	        }
171	
172	        .file-icon {
173	            width: 36px;
174	            height: 36px;
175	            border-radius: 8px;
176	            display: flex;
177	            align-items: center;
178	            justify-content: center;
179	            margin-right: 12px;
180	            font-size: 18px;
181	            flex-shrink: 0;
182	        }
183	
184	        .file-icon.audio { background: rgba(251, 113, 133, 0.15); color: #fb7185; }
185	        .file-icon.image { background: rgba(34, 197, 94, 0.15); color: #22c55e; }
186	        .file-icon.video { background: rgba(234, 179, 8, 0.15); color: #eab308; }
187	        .file-icon.app { background: rgba(168, 85, 247, 0.15); color: #a855f7; }
188	        .file-icon.doc { background: rgba(96, 165, 250, 0.15); color: #60a5fa; }
189	        .file-icon.folder { background: rgba(59, 130, 246, 0.15); color: #3b82f6; }
190	        .file-icon.other { background: rgba(156, 163, 175, 0.15); color: #9ca3af; }
191	
192	        .file-info {
193	            flex: 1;
194	            min-width: 0;
195	        }
196	
197	        .file-name {
198	            font-size: 14px;
199	            font-weight: 500;
200	            white-space: nowrap;
201	            overflow: hidden;
202	            text-overflow: ellipsis;
203	        }
204	
205	        .file-type {
206	            font-size: 12px;
207	            color: #8b949e;
208	            text-transform: uppercase;
209	        }
210	
211	        .file-size {
212	            font-size: 14px;
213	            font-weight: 600;
214	            color: #58a6ff;
215	            margin-left: 16px;
216	            flex-shrink: 0;
217	        }
218	
219	        .type-legend {
220	            margin-top: 16px;
221	            display: flex;
222	            flex-wrap: wrap;
223	            gap: 12px;
224	        }
225	
226	        .legend-item {
227	            display: flex;
228	            align-items: center;
229	            gap: 6px;
230	            font-size: 12px;
231	        }
232	
233	        .legend-dot {
234	            width: 10px;
235	            height: 10px;
236	            border-radius: 50%;
237	        }
238	
239	        ::selection {
240	            background: #58a6ff;
241	            color: #0d1117;
242	        }
243	    </style>
244	</head>
245	<body>
246	    <div class="container">
247	        <h1>Downloads Audit</h1>
248	        <p class="subtitle">Анализ папки загрузок • 685 МБ • 114 файлов</p>
249	
250	        <div class="stats-grid">
251	            <div class="stat-card">
252	                <div class="stat-value">114</div>
253	                <div class="stat-label">Всего файлов</div>
254	            </div>
255	            <div class="stat-card">
256	                <div class="stat-value">685 МБ</div>
257	                <div class="stat-label">Общий размер</div>
258	            </div>
259	            <div class="stat-card">
260	                <div class="stat-value">9</div>
261	                <div class="stat-label">Типов файлов</div>
262	            </div>
263	            <div class="stat-card">
264	                <div class="stat-value">14</div>
265	                <div class="stat-label">Временных файлов Word</div>
266	            </div>
267	        </div>
268	
269	        <div class="dashboard-grid">
270	            <div class="card">
271	                <div class="card-title">Типы файлов</div>
272	                <div class="chart-container">
273	                    <canvas id="typeChart"></canvas>
274	                </div>
275	                <div class="type-legend" id="legend"></div>
276	            </div>
277	
278	            <div class="card">
279	                <div class="card-title">Топ-10 самых больших</div>
280	                <div class="file-list" id="fileList"></div>
281	            </div>
282	        </div>
283	    </div>
284	
285	    <script>
286	        const typeData = {
287	            'HEIC': { count: 43, color: '#22c55e' },
288	            'JPG': { count: 33, color: '#16a34a' },
289	            'PDF': { count: 14, color: '#dc2626' },
290	            'MOV': { count: 3, color: '#eab308' },
291	            'M4A': { count: 2, color: '#fb7185' },
292	            'DOCX': { count: 2, color: '#60a5fa' },
293	            'PKG': { count: 1, color: '#a855f7' },
294	            'DMG': { count: 1, color: '#3b82f6' },
295	            'PNG': { count: 1, color: '#8b5cf6' }
296	        };
297	
298	        const files = [
299	            { name: 'Telegram Desktop', size: '259 МБ', type: 'folder', icon: 'folder' },
300	            { name: '3. Запреты.m4a', size: '133 МБ', type: 'audio', icon: 'audio' },
301	            { name: 'Happ.macOS.universal.dmg', size: '125 МБ', type: 'app', icon: 'app' },
302	            { name: 'node-v24.15.0.pkg', size: '97 МБ', type: 'app', icon: 'app' },
303	            { name: 'Запреты.Прикладная работа.m4a', size: '70 МБ', type: 'audio', icon: 'audio' },
304	            { name: '1_Курс_Целеустроение_Первая_встреча_04_03_2026.docx', size: '48 КБ', type: 'doc', icon: 'doc' },
305	            { name: '2. Конспект Запреты.docx', size: '44 КБ', type: 'doc', icon: 'doc' },
306	            { name: '~$явка на визу в Британию.dotx', size: '4 КБ', type: 'temp', icon: 'other' },
307	            { name: '~$чта. Большая цель - 29.04.2025.docx', size: '4 КБ', type: 'temp', icon: 'other' },
308	            { name: '~$спределение_участников_по_сессиям.docx', size: '4 КБ', type: 'temp', icon: 'other' }
309	        ];
310	
311	        const iconEmoji = {
312	            audio: '🎵',
313	            image: '🖼',
314	            video: '🎬',
315	            app: '💾',
316	            doc: '📄',
317	            folder: '📁',
318	            other: '📎',
319	            temp: '📝'
320	        };
321	
322	        // Doughnut chart
323	        new Chart(document.getElementById('typeChart'), {
324	            type: 'doughnut',
325	            data: {
326	                labels: Object.keys(typeData),
327	                datasets: [{
328	                    data: Object.values(typeData).map(v => v.count),
329	                    backgroundColor: Object.values(typeData).map(v => v.color),
330	                    borderColor: '#161b22',
331	                    borderWidth: 3,
332	                    hoverOffset: 8
333	                }]
334	            },
335	            options: {
336	                responsive: true,
337	                maintainAspectRatio: false,
338	                cutout: '60%',
339	                plugins: {
340	                    legend: { display: false },
341	                    tooltip: {
342	                        backgroundColor: '#21262d',
343	                        titleColor: '#e6edf3',
344	                        bodyColor: '#e6edf3',
345	                        borderColor: '#30363d',
346	                        borderWidth: 1,
347	                        padding: 12,
348	                        cornerRadius: 8,
349	                        callbacks: {
350	                            label: ctx => ` ${ctx.label}: ${ctx.parsed} файлов`
351	                        }
352	                    }
353	                }
354	            }
355	        });
356	
357	        // Custom legend
358	        const legendEl = document.getElementById('legend');
359	        Object.entries(typeData).forEach(([type, { count, color }]) => {
360	            legendEl.innerHTML += `
361	                <div class="legend-item">
362	                    <span class="legend-dot" style="background:${color}"></span>
363	                    <span>${type} (${count})</span>
364	                </div>
365	            `;
366	        });
367	
368	        // File list
369	        const listEl = document.getElementById('fileList');
370	        files.forEach((file, i) => {
371	            listEl.innerHTML += `
372	                <div class="file-item">
373	                    <span class="file-rank ${i < 3 ? 'top3' : ''}">${i + 1}</span>
374	                    <span class="file-icon ${file.icon}">${iconEmoji[file.icon]}</span>
375	                    <div class="file-info">
376	                        <div class="file-name">${file.name}</div>
377	                        <div class="file-type">${file.type}</div>
378	                    </div>
379	                    <span class="file-size">${file.size}</span>
380	                </div>
381	            `;
382	        });
383	    </script>
384	</body>
385	</html>
